class_name AutoPlayController
extends Node
## AutoPlayController - 自动转向控制器
## 在 GuidanceBox 位置创建自动转向触发器

@export var guidance_controller: GuidanceController
@export var enabled: bool = true

var _holder: Node3D
var _triggers: Array[Area3D] = []

func _ready() -> void:
	if Engine.is_editor_hint():
		return
	_create_triggers()

func _create_triggers() -> void:
	if not guidance_controller or not guidance_controller.box_holder:
		push_warning("[AutoPlayController] guidance_controller 或 box_holder 未设置")
		return

	var boxes := guidance_controller.box_holder.get_children()
	if boxes.is_empty():
		return

	# 创建 AutoPlayHolder 父节点
	_holder = Node3D.new()
	_holder.name = "AutoPlayHolder"
	get_tree().current_scene.add_child(_holder)

	# 从第二个 box 开始创建触发器（与 Unity 版本一致）
	for i in range(1, boxes.size()):
		var box := boxes[i]
		if not box is Node3D:
			continue
		var trigger := _create_trigger(box.global_position)
		_triggers.append(trigger)

	set_holder(enabled)

func _create_trigger(pos: Vector3) -> Area3D:
	var area := Area3D.new()
	area.name = "AutoPlayTrigger"

	# 创建碰撞形状 — 使用小球体匹配 trigger_distance
	var collision := CollisionShape3D.new()
	var sphere := SphereShape3D.new()
	sphere.radius = sqrt(0.33)  # 与 AutoPlay.trigger_distance 匹配
	collision.shape = sphere
	area.add_child(collision)

	# 添加 AutoPlay 脚本
	var script := load("res://#Template/[Scripts]/Auto/AutoPlay.gd")
	area.set_script(script)

	area.global_position = pos
	_holder.add_child(area)
	return area

func set_holder(active: bool) -> void:
	if _holder:
		_holder.visible = active
		for trigger in _triggers:
			if trigger is Area3D:
				trigger.set_deferred("monitoring", active)
				trigger.set_deferred("monitorable", active)

